/**
 * Agent activity layer — agents publish PlatformEvents with module='agent'.
 * v1: event contract + registry; real orchestration plugs in later.
 */

import {
  publishActivityEvent,
  listActivityEvents,
  type ActivityEvent,
  ACTIVITY_EVENTS_TABLE,
} from './activity-events';
import { fromActivityEvent, type PlatformEvent } from './platform-events';

export type AgentKind =
  | 'research'
  | 'proposal'
  | 'qa'
  | 'training'
  | 'content'
  | 'launch'
  | 'deployment'
  | (string & {});

export type AgentRunStatus =
  | 'queued'
  | 'running'
  | 'paused'
  | 'review_required'
  | 'completed'
  | 'failed'
  | 'cancelled';

export interface AgentRunInput {
  organizationId: string;
  agentKind: AgentKind;
  task: string;
  status?: AgentRunStatus;
  progress?: number;
  estimatedCompletion?: string;
  reviewRequired?: boolean;
  actionUrl?: string;
  clientSlug?: string;
  projectId?: string;
  metadata?: Record<string, unknown>;
}

export interface AgentRun extends PlatformEvent {
  agentKind: AgentKind;
  status: AgentRunStatus;
  task: string;
  progress: number;
  estimatedCompletion?: string;
  reviewRequired: boolean;
}

export interface AgentDefinition {
  kind: AgentKind;
  label: string;
  description: string;
}

/** Built-in EA agent registry (extend per deploy). */
export const EA_AGENT_REGISTRY: AgentDefinition[] = [
  { kind: 'research', label: 'Research Agent', description: 'Finds opportunities and context' },
  { kind: 'proposal', label: 'Proposal Agent', description: 'Drafts client proposals' },
  { kind: 'qa', label: 'QA Agent', description: 'Tests deployments and flows' },
  { kind: 'training', label: 'Training Agent', description: 'Builds courses and guides' },
  { kind: 'content', label: 'Content Agent', description: 'Prepares newsletters and posts' },
  { kind: 'launch', label: 'Launch Agent', description: 'Runs launch verification' },
  { kind: 'deployment', label: 'Deployment Agent', description: 'Coordinates releases' },
];

export async function publishAgentRun(
  baseId: string,
  tableId = ACTIVITY_EVENTS_TABLE,
  input: AgentRunInput,
): Promise<AgentRun> {
  const status = input.status ?? 'running';
  const progress = clamp(input.progress ?? (status === 'completed' ? 100 : 10), 0, 100);
  const label = EA_AGENT_REGISTRY.find((a) => a.kind === input.agentKind)?.label ?? input.agentKind;

  const record = await publishActivityEvent(baseId, tableId, {
    organizationId: input.organizationId,
    module: 'agent',
    eventType: `agent.${status}`,
    title: `${label}: ${input.task}`,
    summary: statusSummary(status, input.task, progress),
    priority: status === 'review_required' ? 95 : status === 'running' ? 70 : 50,
    metric: `${progress}%`,
    actionLabel: status === 'review_required' ? 'Review' : 'Open',
    actionUrl: input.actionUrl,
    personId: input.clientSlug,
    metadata: {
      agentKind: input.agentKind,
      agentStatus: status,
      task: input.task,
      progress,
      estimatedCompletion: input.estimatedCompletion,
      reviewRequired: input.reviewRequired ?? status === 'review_required',
      clientSlug: input.clientSlug,
      projectId: input.projectId,
      category: 'agent',
      source: 'agent',
      ...input.metadata,
    },
  });

  return toAgentRun(record);
}

export async function listAgentRuns(
  baseId: string,
  tableId = ACTIVITY_EVENTS_TABLE,
  organizationId: string,
  maxRecords = 20,
): Promise<AgentRun[]> {
  const events = await listActivityEvents(baseId, tableId, {
    organizationId,
    module: 'agent',
    maxRecords,
  });
  return events.map(toAgentRun);
}

export function toAgentRun(event: ActivityEvent): AgentRun {
  const platform = fromActivityEvent(event);
  const meta = event.metadata;

  return {
    ...platform,
    source: 'agent',
    category: 'agent',
    agentKind: (readStr(meta.agentKind) || 'research') as AgentKind,
    status: (readStr(meta.agentStatus) || 'running') as AgentRunStatus,
    task: readStr(meta.task) || event.title,
    progress: clamp(readNum(meta.progress) ?? 0, 0, 100),
    estimatedCompletion: readStr(meta.estimatedCompletion) || undefined,
    reviewRequired: Boolean(meta.reviewRequired) || meta.agentStatus === 'review_required',
  };
}

export function isActiveAgent(run: AgentRun): boolean {
  return run.status === 'running' || run.status === 'queued' || run.status === 'review_required';
}

function statusSummary(status: AgentRunStatus, task: string, progress: number): string {
  switch (status) {
    case 'review_required':
      return `${task} — ready for your review`;
    case 'completed':
      return `${task} — completed`;
    case 'failed':
      return `${task} — needs attention`;
    case 'paused':
      return `${task} — paused at ${progress}%`;
    case 'queued':
      return `${task} — queued`;
    default:
      return `${task} — ${progress}% complete`;
  }
}

function readStr(value: unknown): string {
  return typeof value === 'string' ? value : '';
}

function readNum(value: unknown): number | undefined {
  return typeof value === 'number' && Number.isFinite(value) ? value : undefined;
}

function clamp(n: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, Math.round(n)));
}
